import{_ as i,o as l,c as e,ag as s}from"./chunks/framework.gU7RhlGX.js";const c=JSON.parse('{"title":"MCP Builder：高质量 MCP Server 开发指南","description":"","frontmatter":{},"headers":[],"relativePath":"mcp/mcp builder.md","filePath":"mcp/mcp builder.md","lastUpdated":1776422487000}'),a={name:"mcp/mcp builder.md"};function n(r,t,o,d,p,h){return l(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="mcp-builder-高质量-mcp-server-开发指南" tabindex="-1">MCP Builder：高质量 MCP Server 开发指南 <a class="header-anchor" href="#mcp-builder-高质量-mcp-server-开发指南" aria-label="Permalink to &quot;MCP Builder：高质量 MCP Server 开发指南&quot;">​</a></h1><p>MCP Builder 是开发、测试和优化 MCP (Model Context Protocol) Server 的权威指南。它旨在帮助开发者构建能够让 LLM 有效与外部服务交互的高质量工具。</p><hr><h2 id="🚀-核心工作流-四阶段开发法" tabindex="-1">🚀 核心工作流：四阶段开发法 <a class="header-anchor" href="#🚀-核心工作流-四阶段开发法" aria-label="Permalink to &quot;🚀 核心工作流：四阶段开发法&quot;">​</a></h2><p>创建一个高质量的 MCP Server 分为四个关键阶段：</p><h3 id="第一阶段-深度研究与规划-deep-research-planning" tabindex="-1">第一阶段：深度研究与规划 (Deep Research &amp; Planning) <a class="header-anchor" href="#第一阶段-深度研究与规划-deep-research-planning" aria-label="Permalink to &quot;第一阶段：深度研究与规划 (Deep Research &amp; Planning)&quot;">​</a></h3><ol><li><strong>理解现代 MCP 设计</strong>： <ul><li><strong>API 覆盖 vs. 工作流工具</strong>：平衡全面 API 端点覆盖与专用工作流工具。优先考虑全面的 API 覆盖，让 Agent 具备灵活组合操作的能力。</li><li><strong>工具命名与发现</strong>：使用一致的前缀（如 <code>github_create_issue</code>）和动作导向的命名。</li><li><strong>上下文管理</strong>：提供简洁且聚焦的数据，支持过滤和分页，避免无关信息干扰。</li><li><strong>可操作的错误消息</strong>：错误信息应指导 Agent 解决问题，并提供具体建议。</li></ul></li><li><strong>研究协议文档</strong>： <ul><li>从 <a href="https://modelcontextprotocol.io/sitemap.xml" target="_blank" rel="noreferrer">modelcontextprotocol.io/sitemap.xml</a> 获取协议地图。</li><li><strong>技巧</strong>：访问特定页面时，可以尝试在 URL 后添加 <code>.md</code> 后缀来直接获取 Markdown 格式内容（例如：<code>https://modelcontextprotocol.io/specification/draft.md</code>）。</li></ul></li><li><strong>规划实施方案</strong>：分析目标服务的 API 文档，确定核心端点、认证要求及数据模型。</li></ol><h3 id="第二阶段-实施阶段-implementation" tabindex="-1">第二阶段：实施阶段 (Implementation) <a class="header-anchor" href="#第二阶段-实施阶段-implementation" aria-label="Permalink to &quot;第二阶段：实施阶段 (Implementation)&quot;">​</a></h3><ol><li><strong>设置项目结构</strong>： <ul><li><strong>TypeScript (推荐)</strong>：使用 MCP SDK，支持 Zod 模式验证。</li><li><strong>Python</strong>：使用 FastMCP / Python SDK，支持 Pydantic 模型。</li></ul></li><li><strong>构建核心基础设施</strong>： <ul><li>实现带认证的 API 客户端。</li><li>编写统一的错误处理助手。</li><li>支持分页和响应格式化（JSON/Markdown）。</li></ul></li><li><strong>实现工具 (Tools)</strong>： <ul><li><strong>输入模式</strong>：使用 Zod 或 Pydantic 定义严格的约束、描述和示例。</li><li><strong>输出模式</strong>：定义 <code>outputSchema</code> 和 <code>structuredContent</code> 以帮助客户端处理数据。</li><li><strong>注解 (Annotations)</strong>：正确标记 <code>readOnlyHint</code>, <code>destructiveHint</code>, <code>idempotentHint</code>, <code>openWorldHint</code> 等。</li></ul></li></ol><h3 id="第三阶段-审查与测试-review-testing" tabindex="-1">第三阶段：审查与测试 (Review &amp; Testing) <a class="header-anchor" href="#第三阶段-审查与测试-review-testing" aria-label="Permalink to &quot;第三阶段：审查与测试 (Review &amp; Testing)&quot;">​</a></h3><ol><li><strong>代码质量审查</strong>： <ul><li>遵循 DRY 原则，避免重复代码。</li><li>确保类型全覆盖（Full type coverage）。</li><li>提供清晰、准确的工具描述。</li></ul></li><li><strong>构建与验证</strong>： <ul><li>使用 <strong>MCP Inspector</strong> (<code>npx @modelcontextprotocol/inspector</code>) 进行实时测试。</li><li>验证编译是否通过（如 <code>npm run build</code> 或 <code>python -m py_compile</code>）。</li></ul></li></ol><h3 id="第四阶段-创建评估-create-evaluations" tabindex="-1">第四阶段：创建评估 (Create Evaluations) <a class="header-anchor" href="#第四阶段-创建评估-create-evaluations" aria-label="Permalink to &quot;第四阶段：创建评估 (Create Evaluations)&quot;">​</a></h3><p>构建 10 个以上复杂、真实的评估问题。评估文件通常使用 XML 格式存储：</p><div class="language-xml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">evaluation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">qa_pair</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">question</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;具体的、复杂的、需要多步工具调用的问题...&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">question</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">answer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;唯一且可比对的标准答案&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">answer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">qa_pair</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">evaluation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>评估要求</strong>：</p><ul><li><strong>独立性</strong>：各问题互不依赖。</li><li><strong>只读性</strong>：仅执行非破坏性操作（Read-only）。</li><li><strong>复杂性</strong>：需要多次工具调用和深度探索。</li><li><strong>稳定性</strong>：答案不会随时间轻易改变。</li></ul><hr><h2 id="🛠️-推荐技术栈" tabindex="-1">🛠️ 推荐技术栈 <a class="header-anchor" href="#🛠️-推荐技术栈" aria-label="Permalink to &quot;🛠️ 推荐技术栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">推荐选择 (Recommended)</th><th style="text-align:left;">理由</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>编程语言</strong></td><td style="text-align:left;"><strong>TypeScript</strong></td><td style="text-align:left;">SDK 支持度最高，类型安全，AI 生成代码效果更好。</td></tr><tr><td style="text-align:left;"><strong>验证库</strong></td><td style="text-align:left;"><strong>Zod</strong> (TS) / <strong>Pydantic</strong> (Py)</td><td style="text-align:left;">强大的模式验证和清晰的元数据描述。</td></tr><tr><td style="text-align:left;"><strong>传输协议</strong></td><td style="text-align:left;"><strong>stdio</strong> (本地) / <strong>HTTP</strong> (远程)</td><td style="text-align:left;">灵活适配各种运行环境。</td></tr><tr><td style="text-align:left;"><strong>数据格式</strong></td><td style="text-align:left;"><strong>无状态 JSON</strong></td><td style="text-align:left;">易于扩展和维护。</td></tr></tbody></table><hr><h2 id="✨-质量标准清单-quality-checklist" tabindex="-1">✨ 质量标准清单 (Quality Checklist) <a class="header-anchor" href="#✨-质量标准清单-quality-checklist" aria-label="Permalink to &quot;✨ 质量标准清单 (Quality Checklist)&quot;">​</a></h2><ul><li>[ ] 符合 DRY 原则，无冗余代码。</li><li>[ ] 错误响应具备可操作性（Actionable instructions）。</li><li>[ ] 所有的工具（Tools）都有准确的模式（Schema）描述和示例。</li><li>[ ] 关键操作已添加 Hint 注解。</li><li>[ ] 包含 10 个以上的评估案例（Evaluations）。</li><li>[ ] 处理了分页和长内容限制。</li></ul><hr><blockquote><p>来源参考：</p><ul><li><a href="https://github.com/anthropics/skills/blob/main/skills/mcp-builder/SKILL.md" target="_blank" rel="noreferrer">Anthropic MCP Builder Skill</a></li></ul></blockquote>`,24)])])}const u=i(a,[["render",n]]);export{c as __pageData,u as default};
